INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (905, 19050041, 10, 107611, "シズルさまにエリコさま、\nどうかされたのですか？", 0, 0, 1, 0, 11, 0.5);
