INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (923, 19230017, 10, 115711, "ここメルクリゾートではプールサイドで\nたい焼きを売る怪人の噂がある。", 0, 0, 1, 0, 11, 0.5);
