INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (943, 19430034, 7, 117411, "はぁ、レイ様…♡\n流れる姿も麗しいですね。\nずっと見ていられるぅ…", 0, 0, 1, 0, 11, 1);
