INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (944, 19440038, 10, 107911, "こんなに人がいっぱいいる商機、\n見逃すわけにはいかないにゃ！", 0, 0, 1, 0, 11, 1);
