INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (944, 19440043, 7, 126811, "それ、アキノさんの許可とってるの？\nもし無許可だったら怒られるわよ？", 0, 0, 1, 0, 11, 1);
